import React from 'react'
import { ListItem } from '@fs/zion-ui'
import { SocialEmailOpen } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { useChatState } from '../providers/ChatStateProvider'
import useChatLog from '../hooks/useChatLog'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import { hasUnread } from '../hooks/useHasUnreadChats'

export default function ChatHeaderMarkAllRead({ onClick }) {
  const [t] = useTranslation()
  const { client } = useChatState()
  const { log, track } = useChatLog({ component: '[ChatHeaderMarkAllRead]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  const handleClick = (e) => {
    onClick?.(e)
    track({ link_name: 'Chat:Mark All Chats as Read' })
    try {
      client.markChannelsRead()
      hasUnread({ refreshCache: true })
    } catch (error) {
      handleBasicError(error, { moreInfo: 'Problem calling client.markChannelsRead()' })
    }
  }

  return (
    <ListItem
      data-testid="mark-all-read"
      onClick={handleClick}
      primaryText={t('chat.mark-all-read.action', 'Mark All Chats as Read')}
      startElement={<ListItem.Icon Icon={SocialEmailOpen} />}
      dense
    />
  )
}
