import { Divider, ListItem, MenuOverlay } from '@fs/zion-ui'
import {
  ContentFlag,
  ControlHide,
  ControlList,
  MenuClose,
  Notice,
  NoticeDoNot,
  NoticeMute,
  Person,
  SocialEmailOpen,
  ControlView,
  LogoFamilysearch,
} from '@fs/zion-icon'
import React from 'react'
import { useTranslation } from 'react-i18next'
import { useHistory } from '@fs/zion-router'
import { useUsabilla } from '@fs/zion-usabilla'
import ChatHeaderDarkModeToggle from '../chat-header/ChatHeaderDarkModeToggle'
import ChatHeaderSoundToggle from '../chat-header/ChatHeaderSoundToggle'
import ChatHeaderMarkAllRead from '../chat-header/ChatHeaderMarkAllRead'
import { useChannelActions, useRedirectIfOnChannel } from '../hooks/channelHooks'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'

export default function ChatChannelActionsMenuOverlay({
  menuOverlay,
  isHeader,
  channel,
  reportAbuseOverlay,
  setReportAbuseAdditionalInfo,
  blockUserOverlay,
  usabillaFallbackOverlay,
}) {
  const [t] = useTranslation()
  const history = useHistory()

  // Usabilla feedback setup
  const { open } = useUsabilla({
    url: '//w.usabilla.com/ec08e87af7f1.js',
  })

  // Usabilla feedback handler with fallback support
  const handleUsabillaFeedback = async () => {
    const wasAbleToOpen = await open()
    if (!wasAbleToOpen) {
      // Ad-blocker detected, show fallback overlay
      usabillaFallbackOverlay.open()
    }
  }
  const {
    displayMarkChannelRead,
    displayMuteChannel,
    displayUnmuteChannel,
    displayLeaveChannel,
    displayHideChannel,
    displayGroupDetails,
    displayReportAbuse,
    displayBlockUser,
    displayViewHiddenChats,
    name,
    markChannelRead,
    muteChannel,
    unmuteChannel,
    leaveChannel,
    hideChannel,
    getReportAbuseInfo,
  } = useChannelActions({ channel, isHeader })
  const redirectIfOnChannel = useRedirectIfOnChannel(channel)

  return (
    <MenuOverlay {...menuOverlay} inline={false}>
      {displayGroupDetails && (
        <ListItem
          data-testid="details"
          primaryText={t('chat.generic-details.action', 'Details')}
          startElement={<ListItem.Icon Icon={ControlList} />}
          onClick={() => history.push(buildChatRoute(CHAT_ROUTE_KEY.CHAT_DETAILS, { cid: channel.cid }))}
          dense
        />
      )}
      {displayMarkChannelRead && (
        <ListItem
          data-testid="mark-read"
          startElement={<ListItem.Icon Icon={SocialEmailOpen} />}
          primaryText={t('chat.mark-read.action', 'Mark Chat as Read')}
          onClick={markChannelRead}
          dense
        />
      )}
      {displayUnmuteChannel && (
        <ListItem
          data-testid="unmute"
          startElement={<ListItem.Icon Icon={NoticeMute} />}
          primaryText={t('chat.unmute-chat.action', 'Unmute Chat')}
          onClick={unmuteChannel}
          dense
        />
      )}
      {displayMuteChannel && (
        <ListItem
          data-testid="mute"
          startElement={<ListItem.Icon Icon={Notice} />}
          primaryText={t('chat.mute-chat.action', 'Mute Chat')}
          onClick={muteChannel}
          dense
        />
      )}
      {displayLeaveChannel && (
        <ListItem
          data-testid="leave-chat-group"
          startElement={<ListItem.Icon Icon={MenuClose} />}
          primaryText={t('chat.leave-chat.action', 'Leave')}
          onClick={() => leaveChannel().then(redirectIfOnChannel)}
          dense
        />
      )}
      {displayHideChannel && (
        <ListItem
          data-testid="hide-chat-group"
          startElement={<ListItem.Icon Icon={ControlView} />}
          primaryText={t('chat.hide-chat.action', 'Hide Chat')}
          onClick={() => hideChannel().then(redirectIfOnChannel)}
          dense
        />
      )}
      {displayBlockUser && (
        <ListItem
          data-testid="block-user"
          onClick={blockUserOverlay.handleClick}
          primaryText={t('chat.block-user.action', 'Block {name}', { name })}
          startElement={<ListItem.Icon Icon={NoticeDoNot} />}
          dense
        />
      )}
      {isHeader && displayReportAbuse && (
        <>
          <ListItem
            data-testid="report-abuse"
            onClick={async (event) => {
              setReportAbuseAdditionalInfo(await getReportAbuseInfo())
              reportAbuseOverlay.handleClick(event)
            }}
            primaryText={t('common-ui:report-abuse.action', 'Report Abuse')}
            startElement={<ListItem.Icon Icon={ContentFlag} />}
            dense
          />
          <Divider marginY="nano" />
        </>
      )}
      {isHeader && (
        <>
          <ChatHeaderSoundToggle />
          <ChatHeaderMarkAllRead onClick={menuOverlay.handleClick} />
          <ChatHeaderDarkModeToggle />
          <ListItem
            linkName="Chat:View User Profile"
            data-testid="profile"
            to="/identity/settings/profile"
            primaryText={t('chat.profile.action', 'View My Profile')}
            startElement={<ListItem.Icon Icon={Person} />}
            external
            target="_blank"
            dense
          />
        </>
      )}
      {isHeader && (
        <ListItem
          data-testid="display-blocked-users"
          onClick={() => history.push(buildChatRoute(CHAT_ROUTE_KEY.BLOCKED))}
          primaryText={t('chat.display-blocked-users.action', 'View Blocked Users')}
          startElement={<ListItem.Icon Icon={NoticeDoNot} />}
          dense
        />
      )}
      {isHeader && displayViewHiddenChats && (
        <ListItem
          dense
          data-testid="display-hidden-channels"
          onClick={() => history.push(buildChatRoute(CHAT_ROUTE_KEY.HIDDEN))}
          primaryText={t('chat.display-hidden-channels.action', 'View Hidden Chats')}
          startElement={<ListItem.Icon Icon={ControlHide} />}
        />
      )}
      {isHeader && (
        <>
          <Divider marginY="nano" />
          <ListItem
            data-testid="usabilla"
            onClick={handleUsabillaFeedback}
            primaryText={t('chat.display-usabilla.action', 'Give Chat Feedback')}
            dense
            startElement={<ListItem.Icon Icon={LogoFamilysearch} />}
          />
        </>
      )}
    </MenuOverlay>
  )
}
