import { ControlBrightnessMore, ControlDark } from '@fs/zion-icon'
import { ListItem } from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'
import { LOG_LEVEL } from '../global/chatLog'
import useChatLog from '../hooks/useChatLog'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import { CHAT_PREF, setChatPreference } from '../services/chatUserPreferenceService/chatUserPreferenceService'

export default function ChatHeaderDarkModeToggle() {
  const [t] = useTranslation()
  const { log, track } = useChatLog({ component: '[ChatHeaderDarkModeToggle]' })

  const chatDispatch = useChatDispatch()
  const { darkMode } = useChatState()

  const toggleDarkMode = async () => {
    try {
      const newDarkMode = !darkMode
      chatDispatch({
        type: CHAT_ACTIONS.DARK_MODE,
        darkMode: newDarkMode,
      })
      await setChatPreference(CHAT_PREF.DARK_MODE, newDarkMode)
      track({ link_name: `Chat:Turn Dark Mode ${newDarkMode ? 'on' : 'off'}` })
    } catch (err) {
      log({ msg: `setPreference (${CHAT_PREF.DARK_MODE}) failed! - ${err}`, level: LOG_LEVEL.ERROR })
    }
  }

  return (
    <ListItem
      data-testid={darkMode ? 'disable-dark-mode' : 'enable-dark-mode'}
      onClick={toggleDarkMode}
      primaryText={
        darkMode
          ? t('chat.turn-dark-mode-off.action', 'Turn Dark Mode Off')
          : t('chat.turn-dark-mode-on.action', 'Turn Dark Mode On')
      }
      startElement={<ListItem.Icon Icon={darkMode ? ControlDark : ControlBrightnessMore} />}
      dense
    />
  )
}
