import React from 'react'
import { useTranslation } from 'react-i18next'
import { ListItem } from '@fs/zion-ui'
import { MediaVolume } from '@fs/zion-icon'
import { LOG_LEVEL } from '../global/chatLog'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import { CHAT_PREF, setChatPreference } from '../services/chatUserPreferenceService/chatUserPreferenceService'
import useChatLog from '../hooks/useChatLog'

export default function ChatHeaderSoundToggle() {
  const [t] = useTranslation()
  const chatDispatch = useChatDispatch()
  const { soundEnabled } = useChatState()
  const { log, track } = useChatLog({ component: '[ChatHeaderSoundToggle]' })

  const handleChange = async () => {
    const newSoundEnabled = !soundEnabled
    try {
      track({ link_name: `Chat:Turn Sound ${newSoundEnabled ? 'on' : 'off'}` })
      chatDispatch({ type: CHAT_ACTIONS.SET_SOUND_ENABLED, soundEnabled: newSoundEnabled })
      await setChatPreference(CHAT_PREF.SOUND_ENABLED, newSoundEnabled)
    } catch (err) {
      log({ msg: `setPreference (soundEnabled) failed! - ${err}`, level: LOG_LEVEL.ERROR })
    }
  }

  return (
    <ListItem
      data-testid={soundEnabled ? 'enable-sound' : 'disable-sound'}
      onClick={handleChange}
      primaryText={
        soundEnabled
          ? t('chat.turn-sound-off.action', 'Turn Sound Off')
          : t('chat.turn-sound-on.action', 'Turn Sound On')
      }
      startElement={<ListItem.Icon Icon={MediaVolume} toggle={!soundEnabled} />}
      dense
    />
  )
}
